#!/usr/bin/env node
/**
 * EXP-251 — Phase B3 design-system prefix unification.
 *
 * Renames component classes from ad-hoc prefixes to a unified ds-* prefix.
 *
 * Strategy (4 passes per file):
 *   1. class="..." HTML attributes — tokenize value on whitespace, rename matching tokens.
 *   2. class=\"...\" JSON-escaped attributes (sections.json, wins.json) — same.
 *   3. CSS selectors: `.NAME` followed by CSS terminator — rename to `.NEWNAME`.
 *   4. DOM API calls: querySelectorAll/closest/classList.X with bare class names — rename.
 *
 * Pass 3 explicitly excludes contexts where a JS variable named like a class
 * would otherwise be matched (e.g., `const evidence = ...`). Boundary chars are
 * limited to: `.`-prefix (CSS) for pass 3, attribute quotes for pass 1/2,
 * and explicit DOM API patterns for pass 4.
 *
 * Run from repo root: `node monitor/analyst/expansions/EXP-251-rename.js`
 *
 * Verification:
 *   - The script's own verifier reports zero unrenamed occurrences across all 4 contexts.
 *   - Run `node test.js` after applying the test.js patches table from the EXP.
 */

const fs = require('fs');
const path = require('path');

const RENAMES = [
  ['ts-related-callout', 'ds-ts-related-callout'],
  ['stance-statement', 'ds-stance-statement'],
  ['vb-bar-container', 'ds-vb-bar-container'],
  ['verdict-bar-row', 'ds-verdict-bar-row'],
  ['verdict-legend', 'ds-verdict-legend'],
  ['verdict-badge', 'ds-verdict-badge'],
  ['breaking-news', 'ds-breaking-news'],
  ['legend-swatch', 'ds-legend-swatch'],
  ['callout-line', 'ds-callout-line'],
  ['title-block', 'ds-title-block'],
  ['stance-statement', 'ds-stance-statement'],
  ['section-nav', 'ds-section-nav'],
  ['sc-breakdown', 'ds-sc-breakdown'],
  ['verdict-bars', 'ds-verdict-bars'],
  ['verdict-tag', 'ds-verdict-tag'],
  ['win-section', 'ds-win-section'],
  ['pie-callout', 'ds-pie-callout'],
  ['sc-sublabel', 'ds-sc-sublabel'],
  ['tab-content', 'ds-tab-content'],
  ['skip-link', 'ds-skip-link'],
  ['scorecard', 'ds-scorecard'],
  ['sc-domains', 'ds-sc-domains'],
  ['downloads', 'ds-downloads'],
  ['pred-meta', 'ds-pred-meta'],
  ['pie-slice', 'ds-pie-slice'],
  ['pie-label', 'ds-pie-label'],
  ['nav-prev', 'ds-nav-prev'],
  ['nav-next', 'ds-nav-next'],
  ['vb-glyph', 'ds-vb-glyph'],
  ['vb-label', 'ds-vb-label'],
  ['tab-bar', 'ds-tab-bar'],
  ['tab-btn', 'ds-tab-btn'],
  ['bn-date', 'ds-bn-date'],
  ['bn-text', 'ds-bn-text'],
  ['bn-item', 'ds-bn-item'],
  ['ca-icon', 'ds-ca-icon'],
  ['ca-label', 'ds-ca-label'],
  ['ca-tags', 'ds-ca-tags'],
  ['vb-rows', 'ds-vb-rows'],
  ['vb-bar', 'ds-vb-bar'],
  ['dl-card', 'ds-dl-card'],
  ['dl-icon', 'ds-dl-icon'],
  ['dl-label', 'ds-dl-label'],
  ['vb-caption', 'ds-vb-caption'],
  ['vb-count', 'ds-vb-count'],
  ['vb-heading', 'ds-vb-heading'],
  ['vb-pct', 'ds-vb-pct'],
  ['sc-hero', 'ds-sc-hero'],
  ['sc-card', 'ds-sc-card'],
  ['sc-label', 'ds-sc-label'],
  ['sc-number', 'ds-sc-number'],
  ['bn-header', 'ds-bn-header'],
  ['ca-tag', 'ds-ca-tag'],
  ['sc-sm', 'ds-sc-sm'],
  ['evidence', 'ds-evidence'],
  ['subtitle', 'ds-subtitle'],
  ['toc', 'ds-toc'],
  ['meta', 'ds-meta'],
  ['vl', 'ds-vl']
];

// De-dupe (some entries above may appear twice for clarity)
const RENAME_MAP = new Map(RENAMES);
const RENAMES_LONGEST_FIRST = [...RENAME_MAP.entries()]
  .sort((a, b) => b[0].length - a[0].length);

const FILES = [
  'build-scripts/generate-html.js',
  'data/sections.json',
  'data/wins.json',
  'test.js'
];

function escapeRegex(s) {
  return s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

// Rename a class= attribute value, preserving ${...} interpolations.
function renameValue(value) {
  // Tokenize on whitespace; lookup each token in the rename map.
  return value.replace(/[^\s]+/g, token => {
    // Strip a leading '.' if present (CSS selector inside string), preserve trailing punctuation.
    return RENAME_MAP.get(token) || token;
  });
}

// Pass 1: HTML class="..." and class='...'
function passClassAttrHtml(text) {
  return text
    .replace(/class\s*=\s*"([^"]*)"/g, (m, v) => 'class="' + renameValue(v) + '"')
    .replace(/class\s*=\s*'([^']*)'/g, (m, v) => "class='" + renameValue(v) + "'");
}

// Pass 2: JSON-escaped class=\"...\"
function passClassAttrJson(text) {
  return text.replace(/class\s*=\s*\\"([^"\\]*)\\"/g, (m, v) => 'class=\\"' + renameValue(v) + '\\"');
}

// Pass 3: CSS selectors `.NAME` followed by CSS terminator
function passCssSelectors(text) {
  for (const [oldName, newName] of RENAMES_LONGEST_FIRST) {
    // Match `.OLDNAME` followed by whitespace, dot, comma, colon, semicolon,
    // brace, paren, child/sibling combinators, square-bracket, exclamation, or backslash (regex literal context).
    const re = new RegExp('\\.' + escapeRegex(oldName) + '(?=[\\s.,:;{}>+~)\\[!\\\\])', 'g');
    text = text.replace(re, '.' + newName);
  }
  return text;
}

// Pass 4: DOM API calls with class names as string args
function passDomApi(text) {
  // querySelectorAll('.NAME'), querySelector('.NAME'), closest('.NAME'),
  // getElementsByClassName('NAME'), classList.add/remove/contains/toggle('NAME').
  // For querySelector*/closest, the arg is a CSS selector (with leading dot).
  // For classList and getElementsByClassName, the arg is a bare class name.
  const dotApiRe = /\b(querySelectorAll|querySelector|closest)\s*\(\s*(['"])\.([\w-]+)\2/g;
  text = text.replace(dotApiRe, (m, fn, q, name) => {
    const renamed = RENAME_MAP.get(name);
    return renamed ? `${fn}(${q}.${renamed}${q}` : m;
  });
  const bareApiRe = /\b(getElementsByClassName|classList\.(?:add|remove|contains|toggle))\s*\(\s*(['"])([\w-]+)\2/g;
  text = text.replace(bareApiRe, (m, fn, q, name) => {
    const renamed = RENAME_MAP.get(name);
    return renamed ? `${fn}(${q}${renamed}${q}` : m;
  });
  return text;
}

function processFile(filePath) {
  if (!fs.existsSync(filePath)) {
    return { file: filePath, replacements: 0, skipped: true };
  }
  const before = fs.readFileSync(filePath, 'utf8');
  let text = before;
  text = passClassAttrHtml(text);
  text = passClassAttrJson(text);
  text = passCssSelectors(text);
  text = passDomApi(text);
  if (text !== before) {
    fs.writeFileSync(filePath, text);
  }
  let replacements = 0;
  for (const [oldName, newName] of RENAMES_LONGEST_FIRST) {
    const reNew = new RegExp(escapeRegex(newName), 'g');
    const newCount = (text.match(reNew) || []).length;
    const oldCount = (before.match(reNew) || []).length;
    replacements += newCount - oldCount;
  }
  return { file: filePath, replacements };
}

function verify() {
  // Class-name boundary: char before/after must NOT be a class-name char ([a-zA-Z0-9_-]).
  // \b doesn't work here because '-' is non-word, so \btab-content\b matches inside ds-tab-content.
  const PRE = '(?<![a-zA-Z0-9_-])';
  const POST = '(?![a-zA-Z0-9_-])';
  const errors = [];
  for (const filePath of FILES) {
    if (!fs.existsSync(filePath)) continue;
    const text = fs.readFileSync(filePath, 'utf8');
    for (const [oldName] of RENAMES_LONGEST_FIRST) {
      const oldRe = PRE + escapeRegex(oldName) + POST;
      // 1. Old name as a token inside class="..."  (HTML)
      const reHtmlAttr = new RegExp('class\\s*=\\s*"[^"]*' + oldRe + '[^"]*"', 'g');
      const reJsonAttr = new RegExp('class\\s*=\\s*\\\\"[^"\\\\]*' + oldRe + '[^"\\\\]*\\\\"', 'g');
      const reSingleAttr = new RegExp("class\\s*=\\s*'[^']*" + oldRe + "[^']*'", 'g');
      // 2. Old name as CSS selector — `.OLDNAME` followed by CSS terminator
      const reCss = new RegExp('\\.' + escapeRegex(oldName) + '(?=[\\s.,:;{}>+~)\\[!\\\\])', 'g');
      // 3. Old name as DOM API arg
      const reDom = new RegExp(
        '(?:querySelectorAll|querySelector|closest|getElementsByClassName|classList\\.(?:add|remove|contains|toggle))\\s*\\(\\s*[\'"]\\.?' +
        escapeRegex(oldName) + '[\'"]\\s*\\)', 'g');

      const counts = {
        html_attr:   (text.match(reHtmlAttr) || []).length,
        json_attr:   (text.match(reJsonAttr) || []).length,
        single_attr: (text.match(reSingleAttr) || []).length,
        css:         (text.match(reCss) || []).length,
        dom_api:     (text.match(reDom) || []).length
      };
      for (const [kind, n] of Object.entries(counts)) {
        if (n > 0) {
          errors.push(`${filePath}: '${oldName}' has ${n} unrenamed occurrence(s) in context [${kind}]`);
        }
      }
    }
  }
  return errors;
}

// Known expected residuals — these CANNOT be auto-renamed because they live inside
// JS regex literals where the regex syntax (`[^"]*`) interferes with the class-attr pattern matcher.
// The decider must hand-apply the TEST_JS_PATCHES table to fix these.
const EXPECTED_RESIDUALS = [
  { file: 'test.js', name: 'tab-content', context: 'html_attr', max: 2,
    note: 'regex literals at lines ~269 and ~428: /class="tab-content[^"]*"\\s+id="..."/g — apply TEST_JS_PATCHES.' }
];

function isExpected(err) {
  return EXPECTED_RESIDUALS.some(allowed =>
    err.startsWith(allowed.file + ":") &&
    err.includes(`'${allowed.name}'`) &&
    err.includes(`[${allowed.context}]`));
}

const results = FILES.map(processFile);
console.log('=== Rename results ===');
results.forEach(r => console.log(`  ${r.file}: ${r.skipped ? 'SKIPPED' : r.replacements + ' replacements'}`));
const allErrors = verify();
const unexpectedErrors = allErrors.filter(e => !isExpected(e));
const expectedErrors   = allErrors.filter(e =>  isExpected(e));
if (expectedErrors.length > 0) {
  console.log('=== Expected residuals (apply TEST_JS_PATCHES manually) ===');
  expectedErrors.forEach(e => console.log('  ' + e));
}
if (unexpectedErrors.length > 0) {
  console.error('=== UNEXPECTED VERIFICATION FAILURES (' + unexpectedErrors.length + ') ===');
  unexpectedErrors.slice(0, 25).forEach(e => console.error('  ' + e));
  if (unexpectedErrors.length > 25) console.error(`  ... and ${unexpectedErrors.length - 25} more`);
  process.exit(1);
}
console.log('=== All renames verified clean (expected residuals only) ===');
